mapper.update:
UPDATE ticket_approval_template
SET template_name = #{templateName},
    ticket_type = #{ticketType.code},
    description = #{description},
    enabled = #{enabled}
WHERE id = #{id}

mapper.select:
SELECT id, template_name, ticket_type, description, enabled, created_at, updated_at
FROM ticket_approval_template
WHERE id = #{id}

SELECT id, template_name, ticket_type, description, enabled, created_at, updated_at
FROM ticket_approval_template
WHERE 1 = 1
AND ticket_type = #{ticketType}
AND enabled = #{enabled}
ORDER BY created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1)
FROM ticket_approval_template
WHERE 1 = 1
AND ticket_type = #{ticketType}
AND enabled = #{enabled}

mapper.update:
UPDATE ticket_approval_template
SET enabled = #{enabled}
WHERE id = #{id}
